  ('diplomatic-a3078d07-moex-00455', 'diplomatic-a3078d07', 'diplomatic-a3078d07-moex-111-c655adf3', 'sub-diplomatic-a3078d07-04', NULL, 'single_choice', '依司法院大法官之解釋，有關新聞自由之敘述，下列何者正確？', '["唯有報導政治事務之內容，才受新聞自由之憲法保障", "受新聞自由保障之客體，不包括娛樂與運動新聞", "受新聞自由保障之客體，僅限於報導最終呈現之內容", "受新聞自由保障之主體，包括從事新聞工作之個人與事業在內"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:31+00:00", "source_pdf_sha1": "6102eb7b0a8e", "answer_pdf_sha1": "ec6f6a089ef7", "source_family": "moex-gov-tw", "moex": {"exam_code": "111150", "c": "108", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "111", "exam_name": "111年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、國際經濟商務人員考試、原住民族考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-印尼文組"}'::jsonb, NULL)
